import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { buildICS, downloadICS } from "../ics";

/**
 * "Closing soon" deadlines box, fed by /closing-soon.json — a static file
 * generated by `npm run alerts` (tools/deadline-alerts) and committed to
 * frontend/public/. Renders nothing if the file is missing, empty, or stale.
 */
const TYPE_ICONS = {
  "abstract":     "📝",
  "early-bird":   "💷",
  "registration": "🎟️",
  "hotel":        "🏨",
  "scholarship":  "🎓",
  "other":        "📌",
};

// Export the live deadlines as all-day .ics events. Dates here are ISO
// (YYYY-MM-DD) from the deadline-alerts pipeline, so no parsing ambiguity.
const exportDeadlines = (deadlines) => {
  downloadICS(
    "vetnextstep-deadlines.ics",
    buildICS(deadlines.map((d) => {
      const [y, m, day] = d.date.split("-").map(Number);
      return {
        uid: `${d.id}-${d.type}-${d.date}`,
        summary: `${d.conference} — ${d.label}`,
        start: [y, m, day],
        end: [y, m, day],
        url: d.url,
        description: d.note,
      };
    }))
  );
};

const DeadlinesWidget = ({ limit = 5 }) => {
  const [deadlines, setDeadlines] = useState(null);

  useEffect(() => {
    // Skip during react-snap prerender: days-left values are computed from the
    // visitor's clock, so baking them into static HTML would show stale
    // urgency and cause a hydration mismatch.
    if (typeof navigator !== "undefined" && navigator.userAgent === "ReactSnap") return;
    fetch("/closing-soon.json")
      .then((r) => (r.ok ? r.json() : null))
      .then((data) => {
        if (!data || !Array.isArray(data.deadlines)) return;
        // Re-derive days left from today so a stale file doesn't show wrong urgency;
        // drop anything already past.
        const today = new Date(new Date().toISOString().slice(0, 10) + "T00:00:00Z");
        const live = data.deadlines
          .map((d) => ({
            ...d,
            daysLeft: Math.round((new Date(d.date + "T00:00:00Z") - today) / 86400000),
          }))
          .filter((d) => d.daysLeft >= 0)
          .sort((a, b) => a.daysLeft - b.daysLeft);
        if (live.length > 0) setDeadlines(live);
      })
      .catch(() => {});
  }, []);

  if (!deadlines) return null;

  return (
    <section className="bg-amber-50 border border-amber-200 rounded-xl p-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-base font-semibold text-gray-900">⏰ Deadlines closing soon</h2>
        <Link to="/cpd" className="text-xs font-medium text-blue-600 hover:text-blue-800">
          All conferences →
        </Link>
      </div>
      <ul className="space-y-2.5">
        {deadlines.slice(0, limit).map((d) => (
          <li key={`${d.id}-${d.type}-${d.date}`} className="flex items-start gap-2.5 text-sm">
            <span className="flex-shrink-0">{TYPE_ICONS[d.type] || TYPE_ICONS.other}</span>
            <span className="min-w-0 text-gray-700">
              {d.url ? (
                <a href={d.url} target="_blank" rel="noopener noreferrer" className="font-medium text-gray-900 hover:text-blue-700 hover:underline">
                  {d.conference}
                </a>
              ) : (
                <span className="font-medium text-gray-900">{d.conference}</span>
              )}
              {" — "}{d.label}
            </span>
            <span
              className={`ml-auto flex-shrink-0 px-2 py-0.5 rounded-full text-xs font-semibold ${
                d.daysLeft <= 7 ? "bg-red-100 text-red-700" : "bg-amber-100 text-amber-800"
              }`}
            >
              {d.daysLeft === 0 ? "today" : `${d.daysLeft}d left`}
            </span>
          </li>
        ))}
      </ul>
      <button
        onClick={() => exportDeadlines(deadlines)}
        className="mt-4 inline-flex items-center text-xs font-medium text-amber-800 hover:text-amber-900 underline underline-offset-2"
        title="Download these deadlines as an .ics file for your calendar"
      >
        <svg className="mr-1.5 w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
        Add these deadlines to your calendar (.ics)
      </button>
    </section>
  );
};

export default DeadlinesWidget;
